def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    try:
        original_prs = Presentation(original_ppt_path)
        modified_prs = Presentation(modified_ppt_path)

        # Check if slide count changed
        if len(original_prs.slides) != len(modified_prs.slides):
            return "Slide count changed unexpectedly", 0.0

        changes_found = 0
        total_slides_checked = 0

        # Check slides other than slide 3
        for i, (orig_slide, mod_slide) in enumerate(zip(original_prs.slides, modified_prs.slides)):
            if i == 2:  # Skip slide 3 (0-indexed)
                continue

            total_slides_checked += 1

            # Compare text content
            orig_texts = []
            mod_texts = []

            for shape in orig_slide.shapes:
                if hasattr(shape, 'text'):
                    orig_texts.append(shape.text)

            for shape in mod_slide.shapes:
                if hasattr(shape, 'text'):
                    mod_texts.append(shape.text)

            if orig_texts != mod_texts:
                changes_found += 1

        if changes_found == 0:
            return f"No unintended changes found in {total_slides_checked} other slides", 1.0
        else:
            score = max(0.0, 1.0 - (changes_found / total_slides_checked))
            return f"Found unintended changes in {changes_found} out of {total_slides_checked} slides", score

    except Exception as e:
        return f"Error checking other slides: {str(e)}", 0.5

